    void update(int l, int r, Type val) {

        int lidx = l / SIZE, ridx = r / SIZE;

        // 左端の更新

        lazy_eval(lidx);

        bucket[lidx] = I;

        for(int k=SIZE*lidx; k<SIZE*(lidx+1); k++) {

            if(l <= k && k < r) node[k] = op1(node[k], val, 1);

            bucket[lidx] = op2(bucket[lidx], node[k]);

        }



        if(lidx != ridx) {

            // 真ん中 (lazy を更新)

